var BOLGE_TITLES = {
  marmara:'🌉 Marmara Bölgesi',ege:'🫒 Ege Bölgesi',akdeniz:'🌊 Akdeniz Bölgesi',
  ic:'🏔️ İç Anadolu',karadeniz:'⚓ Karadeniz',dogu:'🏞️ Doğu Anadolu',guneydogu:'☀️ Güneydoğu Anadolu'
};
var ORDER = ['marmara','ege','akdeniz','ic','karadeniz','dogu','guneydogu'];
function card(d){
  var h='<div class="td-card"><div class="td-card-hd"><div class="td-card-name">'+d.name+'</div><div class="td-card-il">'+d.il+'</div></div><div class="td-card-body">';
  if(d.adres) h+='<div class="td-row">📍 <span>'+d.adres+'</span></div>';
  if(d.tel) h+='<div class="td-row">📞 <a href="tel:'+d.tel.replace(/\s/g,'')+'">'+d.tel+'</a></div>';
  h+='</div></div>';
  return h;
}
function render(items){
  var out=document.getElementById('td-out');
  document.getElementById('td-count').textContent=items.length;
  if(!items.length){out.innerHTML='<div class="td-empty">Sonuç bulunamadı.</div>';return;}
  var groups={};
  items.forEach(function(d){if(!groups[d.bolge])groups[d.bolge]=[];groups[d.bolge].push(d);});
  var h='';
  ORDER.forEach(function(b){
    if(!groups[b])return;
    h+='<div class="td-sec-title">'+BOLGE_TITLES[b]+' ('+groups[b].length+')</div>';
    h+='<div class="td-grid">';
    groups[b].forEach(function(d){h+=card(d);});
    h+='</div>';
  });
  out.innerHTML=h;
}
var TD={
  filter:function(bolge,btn){
    document.querySelectorAll('.td-fb').forEach(function(b){b.classList.remove('on');});
    btn.classList.add('on');
    document.getElementById('td-inp').value='';
    render(bolge==='all'?DATA:DATA.filter(function(d){return d.bolge===bolge;}));
  },
  search:function(val){
    var q=val.toLowerCase().trim();
    render(q?DATA.filter(function(d){return (d.name+d.il+d.adres+d.tel).toLowerCase().includes(q);}):DATA);
  }
};
render(DATA);
</script>
